// // This module implements a 3-level decision tree with inputs x0, x1, x2 and outputs y. The output y is determined as follows:
// - If x0 is 0, y is equal to x1.
// - If x0 is 1 and x1 is 0, y is equal to 1.
// - If x0 is 1 and x1 is 1, y is equal to x2.
module decision_tree (
    input wire x0,
    input wire x1,
    input wire x2,
    output wire y
);

assign y = (x0 == 0) ? x1 : ((x1 == 0) ? 0 : x2);

endmodule

